parameters.jsCode:
// Format weekly report
const data = $input.first().json;

const report = {
  period: `${data.start_date} to ${data.end_date}`,
  new_cases: data.new_cases.length,
  cases_by_severity: {
    critical: data.cases.filter(c => c.severity === 'critical').length,
    high: data.cases.filter(c => c.severity === 'high').length,
    medium: data.cases.filter(c => c.severity === 'medium').length
  },
  violations_detected: data.violations.length,
  documents_generated: data.documents.length,
  attorney_assignments: data.assignments.length,
  arweave_uploads: data.arweave_uploads.length,
  pending_reviews: data.pending_reviews.length,
  avg_processing_time: data.avg_processing_time_hours
};

return { json: report };

